index c9fce7b591..06dc0bfddc 100644
--- a/cmd/opampsupervisor/supervisor/commander/commander.go
+++ b/cmd/opampsupervisor/supervisor/commander/commander.go
@@ -95,6 +95,25 @@ func (c *Commander) Restart(ctx context.Context) error {
 	return c.Start(ctx)
 }

+// Reload triggers an in-process reload of the Agent configuration.
+//
+// The OpenTelemetry Collector supports reloading its configuration on receipt of SIGHUP
+// (see https://github.com/open-telemetry/opentelemetry-collector/pull/6000).
+//
+// Returns an error if the agent is not running or if the signal could not be delivered.
+func (c *Commander) Reload(ctx context.Context) error {
+	if c.running.Load() == 0 {
+		return errors.New("cannot reload agent: agent is not running")
+	}
+	if ctx.Err() != nil {
+		return ctx.Err()
+	}
+
+	pid := c.cmd.Process.Pid
+	c.logger.Debug("Reloading agent configuration", zap.Int("pid", pid))
+	return sendReloadSignal(c.cmd.Process)
+}
+
 func (c *Commander) startNormal() error {
 	logFilePath := filepath.Join(c.logsDir, "agent.log")
 	stdoutFile, err := os.Create(logFilePath)
