	}
}

func (s *Supervisor) applyConfigToAgent() (agentStartStatus, error) {
	cfgState := s.cfgState.Load().(*configState)

	// If there is no config to run, stop the agent and don't restart it.
	if cfgState.configMapIsEmpty {
		s.telemetrySettings.Logger.Info("No config present, stopping agent.")
		// Ensure the running collector is stopped.
		if err := s.commander.Stop(context.Background()); err != nil {
			s.telemetrySettings.Logger.Error("Could not stop agent process", zap.Error(err))
		}
		// Persist the config on disk (noop/effective config) for diagnostics.
		if err := os.WriteFile(s.agentConfigFilePath(), []byte(cfgState.mergedConfig), 0o600); err != nil {
			s.telemetrySettings.Logger.Error("Failed to write agent config.", zap.Error(err))
		}
		return agentNotStarting, nil
	}

	// Always persist the config before asking the collector to reload.
	if err := os.WriteFile(s.agentConfigFilePath(), []byte(cfgState.mergedConfig), 0o600); err != nil {
		s.telemetrySettings.Logger.Error("Failed to write agent config.", zap.Error(err))
	}

	// Prefer in-process reload if the agent is running. Otherwise start it.
	if s.commander.IsRunning() {
		s.telemetrySettings.Logger.Debug("Reloading agent due to new config")
		if err := s.commander.Reload(context.Background()); err != nil {
			// Fall back to the previous behavior if reload is unsupported (e.g. Windows)
			// or cannot be delivered.
			s.telemetrySettings.Logger.Debug("Agent reload failed; falling back to restart", zap.Error(err))
			s.stopAgentApplyConfig()
			return s.startAgent()
		}
		// The collector will report updated health/effective config asynchronously.
		return agentStarting, nil
	}

	s.telemetrySettings.Logger.Debug("Starting agent due to new config")
	return s.startAgent()
}

