func TestCommanderReloadSendsSIGHUP(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("SIGHUP reload not supported on Windows")
	}

	// Build a small helper that traps HUP.
	tmp := t.TempDir()
	helperSrc := filepath.Join(tmp, "hup.go")
	helperBin := filepath.Join(tmp, "hup")
	helper := []byte(`package main

import (
	"fmt"
	"os"
	"os/signal"
	"syscall"
)

func main() {
	ch := make(chan os.Signal, 10)
	signal.Notify(ch, syscall.SIGHUP)
	fmt.Println("ready")
	<-ch
	fmt.Println("hup")
}
`)
	if err := os.WriteFile(helperSrc, helper, 0o600); err != nil {
		t.Fatalf("write helper: %v", err)
	}
	cmdBuild := exec.Command("go", "build", "-o", helperBin, helperSrc)
	cmdBuild.Env = append(os.Environ(), "CGO_ENABLED=0")
	out, err := cmdBuild.CombinedOutput()
	if err != nil {
		t.Fatalf("build helper: %v\n%s", err, string(out))
	}

	logsDir := filepath.Join(tmp, "logs")
	if err := os.MkdirAll(logsDir, 0o700); err != nil {
		t.Fatalf("mkdir logs: %v", err)
	}

	c, err := commander.NewCommander(zap.NewNop(), logsDir, config.Agent{Executable: helperBin})
	if err != nil {
		t.Fatalf("new commander: %v", err)
	}
	if err := c.Start(context.Background()); err != nil {
		t.Fatalf("start: %v", err)
	}
	defer c.Stop(context.Background())

	// Wait until helper prints "ready".
	deadline := time.Now().Add(5 * time.Second)
	for {
		b, _ := os.ReadFile(filepath.Join(logsDir, "agent.log"))
		if bytes.Contains(b, []byte("ready")) {
			break
		}
		if time.Now().After(deadline) {
			t.Fatalf("helper never became ready; log=%q", string(b))
		}
		time.Sleep(10 * time.Millisecond)
	}

	if err := c.Reload(context.Background()); err != nil {
		t.Fatalf("reload: %v", err)
	}

	// Wait until helper prints "hup".
	deadline = time.Now().Add(5 * time.Second)
	for {
		b, _ := os.ReadFile(filepath.Join(logsDir, "agent.log"))
		if bytes.Contains(b, []byte("hup")) {
			break
		}
		if time.Now().After(deadline) {
			t.Fatalf("helper never received HUP; log=%q", string(b))
		}
		time.Sleep(10 * time.Millisecond)
	}
}
EOF

