			agentConfigOwnMetricsSection: &atomic.Value{},
			effectiveConfig:              &atomic.Value{},
			agentConn:                    &atomic.Value{},
			opampClient:                  mc,
			customMessageToServer:        make(chan *protobufs.CustomMessage, 10),
